class Solution:
    def swapPairs(self, head):
        dummy = ListNode(0, head); prev = dummy
        while prev.next and prev.next.next:
            a, b = prev.next, prev.next.next
            prev.next = b; a.next = b.next; b.next = a
            prev = a
        return dummy.next

