struct ListNode* swapPairs(struct ListNode* head) {
    struct ListNode dummy = {0, head}, *prev = &dummy;
    while (prev->next && prev->next->next) {
        struct ListNode *a = prev->next, *b = a->next;
        prev->next = b; a->next = b->next; b->next = a;
        prev = a;
    }
    return dummy.next;
}
